   680→impl Fit for LmFit {
   681→    fn coefficients(&self) -> &[f64] {
   682→        &self.coefficients
   683→    }
   684→
   685→    fn fitted(&self) -> &[f64] {
   686→        &self.fitted_values
   687→    }
   688→
   689→    fn residuals(&self) -> &[f64] {
   690→        &self.residuals
   691→    }
   692→
   693→    fn summary(&self) -> ModelSummary {
   694→        use inference::{f_test_p_value, model_f_statistic, t_statistics, t_test_p_values};
   695→
   696→        // Calculate residual standard error: s² = RSS / (n - p)
   697→        let rss: f64 = self.residuals.iter().map(|r| r * r).sum();
   698→        let df_resid = self.df_resid() as f64;
   699→        let mse = if df_resid > 0.0 { rss / df_resid } else { 0.0 };
   700→        let residual_std_error = mse.sqrt();
   701→
   702→        // Calculate Total Sum of Squares (TSS) and R-squared
   703→        let y_mean: f64 = self
   704→            .fitted_values
   705→            .iter()
   706→            .zip(self.residuals.iter())
   707→            .map(|(fitted, resid)| fitted + resid) // y = fitted + residual
   708→            .sum::<f64>()
   709→            / self.n_obs as f64;
   710→
   711→        let tss: f64 = self
   712→            .fitted_values
   713→            .iter()
   714→            .zip(self.residuals.iter())
   715→            .map(|(fitted, resid)| {
   716→                let y = fitted + resid;
   717→                (y - y_mean).powi(2)
   718→            })
   719→            .sum();
   720→
   721→        let r_squared = if tss > 0.0 { 1.0 - rss / tss } else { 0.0 };
   722→
   723→        // Adjusted R-squared: 1 - (RSS/(n-p)) / (TSS/(n-1))
   724→        let n = self.n_obs as f64;
   725→        let p = self.rank as f64;
   726→        let adj_r_squared = if n > 1.0 && p > 0.0 {
   727→            1.0 - (rss / (n - p)) / (tss / (n - 1.0))
   728→        } else {
   729→            r_squared
   730→        };
   731→
   732→        // F-statistic for overall model significance
   733→        // RSS for null model (intercept only) equals TSS
   734→        let df_model = if self.rank > 1 { self.rank - 1 } else { 0 }; // exclude intercept
   735→        let f_statistic = if df_model > 0 {
   736→            model_f_statistic(rss, tss, df_model, self.df_resid())
   737→        } else {
   738→            0.0
   739→        };
   740→
   741→        let f_p_value = if df_model > 0 && self.df_resid() > 0 {
   742→            f_test_p_value(f_statistic, df_model as i32, self.df_resid() as i32)
   743→        } else {
   744→            1.0
   745→        };
   746→
   747→        // Calculate variance-covariance matrix: σ² * (X'X)^(-1)
   748→        // Compute X'X
   749→        let xtx = self.x_matrix.transpose() * &self.x_matrix;
   750→
   751→        // Compute (X'X)^(-1) - use QR decomposition for numerical stability
   752→        let qr = xtx.col_piv_qr();
   753→        let identity = Mat::identity(xtx.nrows(), xtx.ncols());
   754→        let xtx_inv = qr.solve(&identity);
   755→
   756→        // Standard errors are sqrt of diagonal elements of σ² * (X'X)^(-1)
   757→        let std_errors: Vec<f64> = (0..self.coefficients.len())
   758→            .map(|i| (mse * xtx_inv[(i, i)]).sqrt())
   759→            .collect();
   760→
   761→        let t_stats = t_statistics(&self.coefficients, &std_errors);
   762→        let p_values = t_test_p_values(&t_stats, self.df_resid() as i32);
   763→
   764→        let mut coefficient_rows = Vec::new();
   765→        for (i, &coef) in self.coefficients.iter().enumerate() {
   766→            let name = if i == 0 {
   767→                "Intercept".to_string()
   768→            } else {
   769→                format!("X{}", i)
   770→            };
   771→
   772→            coefficient_rows.push(CoefficientRow {
   773→                name,
   774→                estimate: coef,
   775→                std_error: std_errors[i],
   776→                t_value: t_stats[i],
   777→                p_value: p_values[i],
   778→            });
   779→        }
   780→
   781→        ModelSummary {
   782→            coefficients: coefficient_rows,
   783→            r_squared,
   784→            adj_r_squared,
   785→            residual_std_error,
   786→            f_statistic,
   787→            f_p_value,
   788→            df_model,
   789→            df_residual: self.df_resid(),
   790→        }
   791→    }
