   793→    fn bootstrap(&self, n_samples: usize) -> Result<BootstrapResult, ModelError> {
   794→        // Create bootstrap statistic that refits the linear model
   795→        let bootstrap_stat = LmBootstrapStatistic {
   796→            n_params: self.coefficients.len(),
   797→        };
   798→
   799→        let config = BootstrapConfig {
   800→            n_samples,
   801→            seed: Some(42), // For reproducible results
   802→            parallel: true,
   803→        };
   804→
   805→        // Convert faer matrix to ndarray
   806→        let n_cols = self.x_matrix.ncols();
   807→        let mut x_data = Vec::with_capacity(self.n_obs * n_cols);
   808→        for i in 0..self.n_obs {
