   815→                .map_err(|e| ModelError::LinearAlgebra(e.to_string()))?;
   816→
   817→        // Reconstruct y from fitted values and residuals
   818→        let y_data: Vec<f64> = self.fitted_values.iter()
   819→            .zip(self.residuals.iter())
   820→            .map(|(fitted, resid)| fitted + resid)
   821→            .collect();
   822→        let y_view = ndarray::ArrayView1::from(&y_data);
   823→
   824→        bootstrap(x_view, y_view, bootstrap_stat, Some(config))
