  1043→            let name = if i == 0 {
  1044→                "Intercept".to_string()
  1045→            } else {
  1046→                format!("X{}", i)
  1047→            };
  1048→
  1049→            coefficient_rows.push(CoefficientRow {
  1050→                name,
  1051→                estimate: coef,
  1052→                std_error: f64::NAN, // Not meaningful for regularized models
  1053→                t_value: f64::NAN,   // Not meaningful for regularized models
  1054→                p_value: f64::NAN,   // Not meaningful for regularized models
  1055→            });
  1056→        }
  1057→
  1058→        ModelSummary {
  1059→            coefficients: coefficient_rows,
  1060→            r_squared,
  1061→            adj_r_squared,
  1062→            residual_std_error,
  1063→            f_statistic: f64::NAN, // Not meaningful for regularized models
  1064→            f_p_value: f64::NAN,   // Not meaningful for regularized models
  1065→            df_model: 0,           // Not meaningful for regularized models
  1066→            df_residual: df_resid as usize,
  1067→        }
  1068→    }
  1069→
  1070→    fn bootstrap(&self, n_samples: usize) -> Result<BootstrapResult, ModelError> {
  1071→        // Create bootstrap statistic that refits the regularized model
  1072→        let bootstrap_stat = RegularizedBootstrapStatistic {
  1073→            lambda: self.lambda,
  1074→            alpha: self.alpha,
  1075→            n_params: self.coefficients.len(),
  1076→        };
  1077→
  1078→        let config = BootstrapConfig {
  1079→            n_samples,
  1080→            seed: Some(42), // For reproducible results
  1081→            parallel: true,
  1082→        };
  1083→
  1084→        // Convert faer matrix to ndarray
  1085→        let n_cols = self.x_matrix.ncols();
  1086→        let mut x_data = Vec::with_capacity(self.n_obs * n_cols);
  1087→        for i in 0..self.n_obs {
  1088→            for j in 0..n_cols {
  1089→                x_data.push(self.x_matrix[(i, j)]);
  1090→            }
  1091→        }
  1092→        let x_view =
  1093→            ndarray::ArrayView2::from_shape((self.n_obs, n_cols), &x_data)
  1094→                .map_err(|e| ModelError::LinearAlgebra(e.to_string()))?;
  1095→
  1096→        let y_view = ndarray::ArrayView1::from(&self.y_vector);
  1097→
  1098→        bootstrap(x_view, y_view, bootstrap_stat, Some(config))
  1099→            .map_err(|e| ModelError::LinearAlgebra(e.to_string()))
  1100→    }
  1101→}
