  1456→    #[test]
  1457→    fn test_multicollinearity_debug() {
  1458→        // Test with non-collinear data to check if our fix works
  1459→        let n_obs = 8;
  1460→        let x1_values: Vec<f64> = (1..=n_obs).map(|i| i as f64).collect();
  1461→        let x2_values: Vec<f64> = (1..=n_obs)
  1462→            .map(|i| (i as f64) * 0.3 + 0.1 * (i as f64).powi(2))
  1463→            .collect();
  1464→        let y_values: Vec<f64> = x1_values
  1465→            .iter()
  1466→            .zip(x2_values.iter())
  1467→            .map(|(&x1, &x2)| 2.0 + 1.5 * x1 + 0.8 * x2 + 0.1 * x1 * x2.sin())
  1468→            .collect();
  1469→
  1470→        // Design matrix: [1, x1, x2] - now without perfect multicollinearity
  1471→        let mut x_data = Vec::with_capacity(n_obs * 3);
  1472→        for i in 0..n_obs {
  1473→            x_data.push(1.0); // intercept
  1474→            x_data.push(x1_values[i]); // x1
  1475→            x_data.push(x2_values[i]); // x2
  1476→        }
  1477→
  1478→        println!("=== Multiple Regression Debug ===");
  1479→        println!("x1: {:?}", x1_values);
  1480→        println!("x2: {:?}", x2_values);
  1481→        println!("x2 is not perfectly correlated with x1");
  1482→
  1483→        let x_mat = Mat::from_fn(n_obs, 3, |i, j| x_data[i * 3 + j]);
  1484→        let _y_mat = Mat::from_fn(n_obs, 1, |i, _| y_values[i]);
  1485→
  1486→        println!("Design matrix X (first 3 rows):");
  1487→        for i in 0..3 {
  1488→            println!(
  1489→                "  [{}, {}, {}]",
  1490→                x_mat[(i, 0)],
  1491→                x_mat[(i, 1)],
  1492→                x_mat[(i, 2)]
  1493→            );
  1494→        }
  1495→
  1496→        let qr = x_mat.col_piv_qr();
  1497→        let r_matrix = qr.R();
  1498→
  1499→        println!("R matrix diagonal:");
  1500→        for i in 0..r_matrix.nrows().min(r_matrix.ncols()) {
  1501→            println!("  R[{},{}] = {}", i, i, r_matrix[(i, i)]);
  1502→        }
  1503→
  1504→        // Detect rank
  1505→        let tolerance = 1e-12;
  1506→        let mut rank = 0;
  1507→        for i in 0..r_matrix.nrows().min(r_matrix.ncols()) {
  1508→            if r_matrix[(i, i)].abs() > tolerance {
  1509→                rank += 1;
  1510→            }
  1511→        }
  1512→        println!("Detected rank: {} (should be 3 for full rank)", rank);
  1513→
  1514→        let fit = Lm::fit(&x_data, &y_values, n_obs, 3).unwrap();
  1515→        println!("Our coefficients: {:?}", fit.coefficients());
  1516→        println!("Our rank: {}", fit.rank());
  1517→
  1518→        // Check if coefficients are numerically stable
  1519→        for (i, &coef) in fit.coefficients().iter().enumerate() {
  1520→            if coef.abs() > 1e6 {
  1521→                println!(
  1522→                    "WARNING: Coefficient {} is numerically unstable: {}",
  1523→                    i, coef
  1524→                );
  1525→            }
  1526→        }
  1527→    }
