        // ψ'(1/2) = π²/2
        assert_relative_eq!(trigamma(0.5).unwrap(), std::f64::consts::PI.powi(2) / 2.0, epsilon = 1e-10);

        // ψ'(2) = π²/6 - 1
        assert_relative_eq!(trigamma(2.0).unwrap(), std::f64::consts::PI.powi(2) / 6.0 - 1.0, epsilon = 1e-10);

        // Additional known values
        assert_relative_eq!(trigamma(3.0).unwrap(), std::f64::consts::PI.powi(2) / 6.0 - 1.25, epsilon = 1e-10);
        assert_relative_eq!(trigamma(4.0).unwrap(), std::f64::consts::PI.powi(2) / 6.0 - 49.0/36.0, epsilon = 1e-10);

        // Test larger values
        assert_relative_eq!(trigamma(10.0).unwrap(), 0.10516633568168575, epsilon = 1e-10);
    }

