        let reflection_term = std::f64::consts::PI / x.sin().powi(2);
        result += reflection_term * std::f64::consts::PI.cos() / x.sin();
        x = 1.0 - x;
        negative_reflection = true;
    }

    while x < SERIES_CUTOFF {
        result += 1.0 / (x * x);
        x += 1.0;
    }

    let x2 = x * x;
    let x3 = x2 * x;
    let x5 = x3 * x2;
    let x7 = x5 * x2;
    let x9 = x7 * x2;
    let x11 = x9 * x2;

    result += 1.0 / x + 1.0 / (2.0 * x2) + 1.0 / (6.0 * x3)
        - 1.0 / (30.0 * x5) + 1.0 / (42.0 * x7)
        - 1.0 / (30.0 * x9) + 5.0 / (66.0 * x11);

    if negative_reflection {
        result = -result;
    }

    Ok(result)
}

pub fn polygamma(mut x: f64, n: usize) -> Result<f64> {
    if x.is_nan() || x.is_infinite() {
        return Err(SpecialFunctionError::InvalidInput(
            "Input must be finite".to_string(),
        ));
    }

    if n == 0 {
        return Ok(digamma(x));
    }

    if n == 1 {
        return trigamma(x);
    }

    if x <= 0.0 && x == x.floor() {
        return Err(SpecialFunctionError::InvalidInput(
            "Polygamma is undefined at non-positive integers".to_string(),
        ));
    }

    let mut negative_reflection = false;
    let mut result = 0.0;

    if x < 0.0 {
        let pi = std::f64::consts::PI;

        let mut reflection_term = 0.0;
        for k in 0..=n {
            let sign = if (n - k) % 2 == 0 { 1.0 } else { -1.0 };
            let binom = binomial_coefficient(n, k);
            let deriv_cot = derivative_cotangent(pi * x, k);
            reflection_term += sign * binom * deriv_cot;
        }

        result = reflection_term * pi.powi(n as i32 + 1);
        x = 1.0 - x;
        negative_reflection = true;
    }

    while x < SERIES_CUTOFF + n as f64 {
        let sign = if n % 2 == 0 { 1.0 } else { -1.0 };
        result += sign * factorial(n) / x.powi(n as i32 + 1);
        x += 1.0;
    }

    let sign = if n % 2 == 0 { 1.0 } else { -1.0 };
    let nfac = factorial(n);
    let n1fac = factorial(n - 1);

    let xn1 = x.powi(n as i32);
    let xn2 = xn1 * x;
    let xn3 = xn2 * x;

    result += sign * n1fac / xn1
        + sign * nfac / (2.0 * xn2)
        + sign * (n as f64) * nfac * bernoulli_number(2) / (2.0 * xn3);

    if n >= 2 {
        for k in 2..=std::cmp::min(n, 10) {
            let term = sign * factorial(n + 2 * k - 1) * bernoulli_number(2 * k)
                / (factorial(2 * k) * x.powi(n as i32 + 2 * k as i32));
            result += term;
        }
    }

    if negative_reflection && n % 2 == 1 {
        result = -result;
    }

    Ok(result)
}

fn factorial(n: usize) -> f64 {
    match n {
        0 | 1 => 1.0,
        2 => 2.0,
        3 => 6.0,
        4 => 24.0,
        5 => 120.0,
        6 => 720.0,
        7 => 5040.0,
        8 => 40320.0,
        9 => 362880.0,
        10 => 3628800.0,
        11 => 39916800.0,
        12 => 479001600.0,
        _ => (1..=n).map(|i| i as f64).product(),
    }
}

fn binomial_coefficient(n: usize, k: usize) -> f64 {
    if k > n {
        return 0.0;
    }
    if k == 0 || k == n {
        return 1.0;
    }

    let k = k.min(n - k);
    let mut result = 1.0;
    for i in 0..k {
        result *= (n - i) as f64 / (i + 1) as f64;
    }
    result
}

fn bernoulli_number(n: usize) -> f64 {
    match n {
        0 => 1.0,
        1 => -0.5,
        2 => 1.0 / 6.0,
        4 => -1.0 / 30.0,
        6 => 1.0 / 42.0,
        8 => -1.0 / 30.0,
        10 => 5.0 / 66.0,
        12 => -691.0 / 2730.0,
        14 => 7.0 / 6.0,
        16 => -3617.0 / 510.0,
        18 => 43867.0 / 798.0,
        20 => -174611.0 / 330.0,
        _ if n % 2 == 1 && n > 1 => 0.0,
        _ => {
            let mut b = vec![0.0; n + 1];
            b[0] = 1.0;

            for m in 1..=n {
                let mut sum = 0.0;
                for k in 0..m {
                    sum += binomial_coefficient(m + 1, k) * b[k];
                }
                b[m] = -sum / (m as f64 + 1.0);
            }

            b[n]
        }
    }
}

fn derivative_cotangent(x: f64, n: usize) -> f64 {
    if n == 0 {
        return 1.0 / x.tan();
    }

    let sin_x = x.sin();
    let cos_x = x.cos();

    match n {
        1 => -1.0 / sin_x.powi(2),
        2 => 2.0 * cos_x / sin_x.powi(3),
        3 => 2.0 * (1.0 + 2.0 * cos_x.powi(2)) / sin_x.powi(4),
        _ => {
            let mut result = 0.0;
            for k in 0..=n/2 {
                let sign = if k % 2 == 0 { 1.0 } else { -1.0 };
                let coeff = euler_number(n, k);
                result += sign * coeff * cos_x.powi(n as i32 - 2 * k as i32) 
                    / sin_x.powi(n as i32 + 1);
            }
            result
        }
    }
}

fn euler_number(n: usize, k: usize) -> f64 {
    if k > n / 2 {
        return 0.0;
    }

    let mut result = 0.0;
    for j in 0..=k {
        let sign = if (k - j) % 2 == 0 { 1.0 } else { -1.0 };
        let binom = binomial_coefficient(n, 2 * j);
        result += sign * binom * (k - j + 1).pow(n as u32) as f64;
    }

    result * 2.0_f64.powi(k as i32) / factorial(k)
}

