//! Oracle tests for special functions validation against R implementation

use csv::ReaderBuilder;
use special::{psigamma, trigamma, polygamma};
use std::fs::File;
use std::io::Write;
use std::process::Command;
use std::time::{SystemTime, UNIX_EPOCH};

#[cfg(test)]
mod oracle_tests {
    use super::*;

    /// Test psigamma function against R's psigamma
    #[test]
    fn test_oracle_psigamma() {
        if !r_available() {
            println!("Skipping Oracle test: R not available");
            return;
        }

        // Test various x values and derivative orders
        let test_cases = vec![
            (1.0, 0),   // digamma(1)
            (2.0, 0),   // digamma(2)
            (0.5, 0),   // digamma(0.5)
            (1.0, 1),   // trigamma(1)
            (2.0, 1),   // trigamma(2)
            (0.5, 1),   // trigamma(0.5)
            (1.0, 2),   // tetragamma(1)
            (2.5, 2),   // tetragamma(2.5)
            (1.0, 3),   // pentagamma(1)
            (3.0, 3),   // pentagamma(3)
        ];

        let timestamp = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap()
            .as_nanos();
        let data_file = format!("/tmp/psigamma_test_{}_{}.csv", std::process::id(), timestamp);

        // Create CSV data file
        {
            let mut file = File::create(&data_file).unwrap();
            writeln!(file, "x,deriv").unwrap();
            for (x, deriv) in &test_cases {
                writeln!(file, "{},{}", x, deriv).unwrap();
            }
        }

        // Run R oracle
        let r_results = run_r_oracle("psigamma", &data_file).expect("Failed to run R oracle");

        // Compare results with tolerance based on derivative order
        // Higher order derivatives accumulate more numerical error
        for (i, &(x, deriv)) in test_cases.iter().enumerate() {
            let tolerance = if deriv <= 1 { 1e-10 } else { 1e-5 };
            let rust_value = psigamma(x, deriv).unwrap();
            let r_value = r_results.values[i];

            let diff = (rust_value - r_value).abs();
            let rel_diff = if r_value.abs() > 1e-10 {
                diff / r_value.abs()
            } else {
                diff
            };

            assert!(
                rel_diff < tolerance,
                "psigamma({}, {}) differs: Rust = {}, R = {}, rel_diff = {}",
                x, deriv, rust_value, r_value, rel_diff
            );
        }

        println!("✅ psigamma Oracle test passed: All values match R within {} tolerance", tolerance);
        std::fs::remove_file(&data_file).ok();
    }

    /// Test trigamma function specifically against R
    #[test]
    fn test_oracle_trigamma() {
        if !r_available() {
            println!("Skipping Oracle test: R not available");
            return;
        }

        // Test various x values
        let x_values = vec![
            0.5, 1.0, 1.5, 2.0, 2.5, 3.0, 4.0, 5.0,
            10.0, 20.0, 50.0, 100.0
        ];

