//! Oracle tests for special functions validation against R implementation

use csv::ReaderBuilder;
use special::{psigamma, trigamma, polygamma};
use std::fs::File;
use std::io::Write;
use std::process::Command;
use std::time::{SystemTime, UNIX_EPOCH};

#[cfg(test)]
mod oracle_tests {
    use super::*;

    /// Test psigamma function against R's psigamma
    #[test]
    fn test_oracle_psigamma() {
        if !r_available() {
            println!("Skipping Oracle test: R not available");
            return;
        }

        // Test various x values and derivative orders
        let test_cases = vec![
            (1.0, 0),   // digamma(1)
            (2.0, 0),   // digamma(2)
            (0.5, 0),   // digamma(0.5)
            (1.0, 1),   // trigamma(1)
            (2.0, 1),   // trigamma(2)
            (0.5, 1),   // trigamma(0.5)
            (1.0, 2),   // tetragamma(1)
            (2.5, 2),   // tetragamma(2.5)
            (1.0, 3),   // pentagamma(1)
            (3.0, 3),   // pentagamma(3)
        ];

        let timestamp = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap()
            .as_nanos();
        let data_file = format!("/tmp/psigamma_test_{}_{}.csv", std::process::id(), timestamp);

        // Create CSV data file
        {
            let mut file = File::create(&data_file).unwrap();
            writeln!(file, "x,deriv").unwrap();
            for (x, deriv) in &test_cases {
                writeln!(file, "{},{}", x, deriv).unwrap();
            }
        }

        // Run R oracle
        let r_results = run_r_oracle("psigamma", &data_file).expect("Failed to run R oracle");

        // Compare results with tolerance based on derivative order
        // Higher order derivatives accumulate more numerical error
        for (i, &(x, deriv)) in test_cases.iter().enumerate() {
            let tolerance = if deriv <= 1 { 1e-10 } else { 1e-5 };
            let rust_value = psigamma(x, deriv).unwrap();
            let r_value = r_results.values[i];

            let diff = (rust_value - r_value).abs();
            let rel_diff = if r_value.abs() > 1e-10 {
                diff / r_value.abs()
            } else {
                diff
            };

            assert!(
                rel_diff < tolerance,
                "psigamma({}, {}) differs: Rust = {}, R = {}, rel_diff = {}",
                x, deriv, rust_value, r_value, rel_diff
            );
        }

        println!("✅ psigamma Oracle test passed: All values match R within specified tolerances");
        std::fs::remove_file(&data_file).ok();
    }

    /// Test trigamma function specifically against R
    #[test]
    fn test_oracle_trigamma() {
        if !r_available() {
            println!("Skipping Oracle test: R not available");
            return;
        }

        // Test various x values
        let x_values = vec![
            0.5, 1.0, 1.5, 2.0, 2.5, 3.0, 4.0, 5.0,
            10.0, 20.0, 50.0, 100.0
        ];

        let timestamp = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap()
            .as_nanos();
        let data_file = format!("/tmp/trigamma_test_{}_{}.csv", std::process::id(), timestamp);

        // Create CSV data file
        {
            let mut file = File::create(&data_file).unwrap();
            writeln!(file, "x").unwrap();
            for x in &x_values {
                writeln!(file, "{}", x).unwrap();
            }
        }

        // Run R oracle
        let r_results = run_r_oracle("trigamma", &data_file).expect("Failed to run R oracle");

        // Compare results at 1e-8 tolerance (slightly relaxed for numerical precision)
        let tolerance = 1e-8;
        for (i, &x) in x_values.iter().enumerate() {
            let rust_value = trigamma(x).unwrap();
            let r_value = r_results.values[i];

            let diff = (rust_value - r_value).abs();
            let rel_diff = if r_value.abs() > 1e-10 {
                diff / r_value.abs()
            } else {
                diff
            };

            assert!(
                rel_diff < tolerance,
                "trigamma({}) differs: Rust = {}, R = {}, rel_diff = {}",
                x, rust_value, r_value, rel_diff
            );
        }

        println!("✅ trigamma Oracle test passed: All values match R within {} tolerance", tolerance);
        std::fs::remove_file(&data_file).ok();
    }

    /// Test polygamma functions of various orders against R
    #[test]
    fn test_oracle_polygamma() {
        if !r_available() {
            println!("Skipping Oracle test: R not available");
            return;
        }

        // Test various x values and orders
        let test_cases = vec![
            (1.0, 2),   // tetragamma(1)
            (2.0, 2),   // tetragamma(2)
            (1.0, 3),   // pentagamma(1)
            (2.0, 3),   // pentagamma(2)
            (1.0, 4),   // hexagamma(1)
            (2.0, 4),   // hexagamma(2)
            (5.0, 2),   // tetragamma(5)
            (5.0, 3),   // pentagamma(5)
            (10.0, 2),  // tetragamma(10)
            (10.0, 3),  // pentagamma(10)
        ];

        let timestamp = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap()
            .as_nanos();
        let data_file = format!("/tmp/polygamma_test_{}_{}.csv", std::process::id(), timestamp);

        // Create CSV data file
        {
            let mut file = File::create(&data_file).unwrap();
            writeln!(file, "x,n").unwrap();
            for (x, n) in &test_cases {
                writeln!(file, "{},{}", x, n).unwrap();
            }
        }

        // Run R oracle
        let r_results = run_r_oracle("polygamma", &data_file).expect("Failed to run R oracle");

        // Compare results with tolerance based on derivative order
        // Higher order derivatives accumulate more numerical error
        for (i, &(x, n)) in test_cases.iter().enumerate() {
            let tolerance = if n <= 1 { 1e-10 } else { 1e-5 };
            let rust_value = polygamma(x, n).unwrap();
            let r_value = r_results.values[i];

            let diff = (rust_value - r_value).abs();
            let rel_diff = if r_value.abs() > 1e-10 {
                diff / r_value.abs()
            } else {
                diff
            };

            assert!(
                rel_diff < tolerance,
                "polygamma({}, {}) differs: Rust = {}, R = {}, rel_diff = {}",
                x, n, rust_value, r_value, rel_diff
            );
        }

        println!("✅ polygamma Oracle test passed: All values match R within specified tolerances");
        std::fs::remove_file(&data_file).ok();
    }

    #[derive(Debug)]
    struct RResults {
        values: Vec<f64>,
    }

    /// Check if R is available in the system
    fn r_available() -> bool {
        Command::new("Rscript")
            .arg("--version")
            .output()
            .map(|output| output.status.success())
            .unwrap_or(false)
    }

    /// Run R oracle and parse results
    fn run_r_oracle(
        test_type: &str,
        data_file: &str,
    ) -> Result<RResults, Box<dyn std::error::Error>> {
        let timestamp = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap()
            .as_nanos();
        let output_file = format!("/tmp/r_output_{}_{}.csv", std::process::id(), timestamp);

        // Find the Oracle script
        let current_dir = std::env::current_dir()?;
        let mut possible_paths = vec![
            current_dir.join("ci/oracle_r/run.R"),
            current_dir.join("../ci/oracle_r/run.R"),
        ];

        if let Some(parent) = current_dir.parent() {
            possible_paths.push(parent.join("ci/oracle_r/run.R"));
        }

        let script_path = possible_paths
            .iter()
            .find(|p| p.exists())
            .ok_or("Could not find Oracle script")?;

        // Run R oracle script
        let output = Command::new("Rscript")
            .arg(script_path)
            .arg(test_type)
            .arg(data_file)
            .arg(&output_file)
            .output()?;

        if !output.status.success() {
            return Err(format!(
                "R oracle failed: {}",
                String::from_utf8_lossy(&output.stderr)
            )
            .into());
        }

        // Parse R output CSV
        parse_r_output(&output_file)
    }

    /// Parse R oracle output CSV into structured results
    fn parse_r_output(file_path: &str) -> Result<RResults, Box<dyn std::error::Error>> {
        let mut reader = ReaderBuilder::new().from_path(file_path)?;
        let mut values = Vec::new();

        for result in reader.records() {
            let record = result?;
            let metric = &record[0];
            let value_str = &record[1];

            // Skip NA values from R
            if value_str == "NA" {
                continue;
            }

            if metric == "values" {
                let value: f64 = value_str.parse()?;
                values.push(value);
            }
        }

        Ok(RResults { values })
    }
}

